import React from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox"; // Import LoginBox

const AppLayout = ({ children }) => {
  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-50 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col justify-center items-center">
        {/* Header */}
        <header className="bg-indigo-800 text-white py-6 px-8 shadow-md w-full text-center">
          <h1 className="text-xl font-semibold tracking-wide">
            Manage Your Projects Efficiently with <span className="text-yellow-300">Proma</span>
          </h1>
        </header>

        {/* Page Content */}
        <div className="p-6">{children}</div>

        {/* Login Box in Center */}
        <LoginBox />
      </main>
    </div>
  );
};

export default AppLayout;
